<?php session_start();header('Content-Type: application/json');require_once '../common/db_connect.php';if(!isset($_SESSION['user_id'])){http_response_code(401);echo json_encode(['success'=>false,'message'=>'Unauthorized']);exit;}$database=new Database();$db=$database->getConnection();$user_id=(int) $_SESSION['user_id'];$method=$_SERVER['REQUEST_METHOD'];$action=isset($_GET['action'])?trim($_GET['action']):null;$api=new ChatAPI($db,$user_id);switch($method){case 'GET':if($action==='check_read'){$msgId=isset($_GET['message_id'])?(int) $_GET['message_id']:0;$api->checkMessageRead($msgId);}else{$api->getChatData();}break;case 'POST':if($action==='start-new'){$api->startNewChat();}else{$api->sendMessage();}break;case 'PUT':if($action==='mark_read'){$convId=isset($_GET['conversation_id'])?(int) $_GET['conversation_id']:0;$api->markMessagesRead($convId);}elseif($action==='resume'){$api->resumeChat();}else{http_response_code(400);echo json_encode(['success'=>false,'message'=>'Unknown PUT action']);}break;default:http_response_code(405);echo json_encode(['success'=>false,'message'=>'Method not allowed']);}class ChatAPI{private $db;private $uid;public function __construct($db,$uid){$this->db=$db;$this->uid=$uid;}public function getChatData(){$conv=$this->getOrCreateConversation();$this->doMarkRead($conv['id'],'support');echo json_encode(['success'=>true,'data'=>['conversation_id'=>$conv['id'],'status'=>$conv['status'],'support_agent'=>$conv['support_agent'],'messages'=>$this->getMessages($conv['id']),'quick_replies'=>$this->getQuickReplies(),]]);}public function sendMessage(){$body=json_decode(file_get_contents('php://input'),true);$message=isset($body['message'])?trim($body['message']):'';if($message===''){$this->fail('Message cannot be empty');return;}$conv=$this->getOrCreateConversation();$convId=$conv['id'];$msgId=$this->saveMsg($convId,'user',$this->uid,$message,0);$replyText=$this->getAutoReply($message);$hasReply=false;if($replyText!==null){$agentId=$conv['support_agent']?(int) $conv['support_agent']['id']:null;$this->saveMsg($convId,'support',$agentId,$replyText,0);$hasReply=true;}echo json_encode(['success'=>true,'data'=>['id'=>$msgId,'created_at'=>date('Y-m-d H:i:s'),'is_read'=>false,],'auto_reply'=>['has_reply'=>$hasReply,'message'=>$replyText,]]);}public function startNewChat(){$stmt=$this->db->prepare("UPDATE chat_conversations SET status = 'closed' WHERE user_id = ? AND status = 'active'");$stmt->bind_param('i',$this->uid);$stmt->execute();$conv=$this->createConversation();echo json_encode(['success'=>true,'data'=>['conversation_id'=>$conv['id'],'support_agent'=>$conv['support_agent'],'quick_replies'=>$this->getQuickReplies(),'welcome_message'=>"👋 Hi there! Welcome to StayEase Support. How can we help you today?",]]);}public function resumeChat(){$body=json_decode(file_get_contents('php://input'),true);$convId=isset($body['conversation_id'])?(int) $body['conversation_id']:0;if(!$convId){$this->fail('Conversation ID required');return;}$stmt=$this->db->prepare("UPDATE chat_conversations SET status = 'active' WHERE id = ? AND user_id = ?");$stmt->bind_param('ii',$convId,$this->uid);$stmt->execute();if($stmt->affected_rows>0){echo json_encode(['success'=>true]);}else{$this->fail('Conversation not found or already active');}}public function markMessagesRead(int $convId){if(!$convId){$this->fail('Conversation ID required');return;}$stmt=$this->db->prepare("SELECT id FROM chat_conversations WHERE id = ? AND user_id = ? LIMIT 1");$stmt->bind_param('ii',$convId,$this->uid);$stmt->execute();if(!$stmt->get_result()->fetch_assoc()){$this->fail('Not found');return;}$n=$this->doMarkRead($convId,'support');$this->doMarkUserMsgsRead($convId);echo json_encode(['success'=>true,'marked'=>$n]);}public function checkMessageRead(int $msgId){if(!$msgId){$this->fail('message_id required');return;}$stmt=$this->db->prepare("SELECT cm.is_read FROM chat_messages cm\n             JOIN chat_conversations cc ON cc.id = cm.conversation_id\n             WHERE cm.id = ? AND cc.user_id = ? LIMIT 1");$stmt->bind_param('ii',$msgId,$this->uid);$stmt->execute();$row=$stmt->get_result()->fetch_assoc();if(!$row){$this->fail('Message not found');return;}echo json_encode(['success'=>true,'is_read'=>(bool) $row['is_read']]);}private function getOrCreateConversation():array{$conv=$this->getLatestConversation();if(!$conv){$conv=$this->createConversation();}return $conv;}private function getLatestConversation():?array{$stmt=$this->db->prepare("SELECT c.*,\n                    sa.id           AS agent_id,\n                    sa.full_name    AS agent_name,\n                    sa.profile_image AS agent_image,\n                    sa.is_online\n             FROM chat_conversations c\n             LEFT JOIN support_agents sa ON c.support_agent_id = sa.id\n             WHERE c.user_id = ?\n             ORDER BY\n               FIELD(c.status, 'active', 'resolved', 'closed'),\n               c.created_at DESC\n             LIMIT 1");$stmt->bind_param('i',$this->uid);$stmt->execute();$row=$stmt->get_result()->fetch_assoc();if(!$row)return null;return['id'=>(int) $row['id'],'status'=>$row['status'],'support_agent'=>$row['agent_id']?['id'=>(int) $row['agent_id'],'name'=>$row['agent_name'],'profile_image'=>$row['agent_image'],'is_online'=>(int) $row['is_online'],]:null,];}private function createConversation():array{$res=$this->db->query("SELECT sa.id\n             FROM support_agents sa\n             LEFT JOIN chat_conversations cc\n               ON cc.support_agent_id = sa.id AND cc.status = 'active'\n             WHERE sa.is_online = 1\n             GROUP BY sa.id\n             ORDER BY COUNT(cc.id) ASC, sa.last_active DESC\n             LIMIT 1");$agentId=($res&&$res->num_rows>0)?(int) $res->fetch_assoc()['id']:null;$stmt=$this->db->prepare("INSERT INTO chat_conversations (user_id, support_agent_id, status) VALUES (?, ?, 'active')");$stmt->bind_param('ii',$this->uid,$agentId);$stmt->execute();$convId=(int) $stmt->insert_id;$welcome="👋 Hi there! Welcome to StayEase Support. How can we help you today?";$this->saveMsg($convId,'support',$agentId,$welcome,0);return['id'=>$convId,'status'=>'active','support_agent'=>$agentId?$this->getAgent($agentId):null,];}private function getAgent(int $id):?array{$stmt=$this->db->prepare("SELECT id, full_name AS name, profile_image, is_online FROM support_agents WHERE id = ? LIMIT 1");$stmt->bind_param('i',$id);$stmt->execute();$row=$stmt->get_result()->fetch_assoc();if(!$row)return null;return['id'=>(int) $row['id'],'name'=>$row['name'],'profile_image'=>$row['profile_image'],'is_online'=>(int) $row['is_online'],];}private function getMessages(int $convId):array{$stmt=$this->db->prepare("SELECT id, sender_type, sender_id, message, is_read, created_at\n             FROM chat_messages\n             WHERE conversation_id = ?\n             ORDER BY created_at ASC, id ASC");$stmt->bind_param('i',$convId);$stmt->execute();$res=$stmt->get_result();$msgs=[];while($row=$res->fetch_assoc()){$msgs[]=['id'=>(int) $row['id'],'sender_type'=>$row['sender_type'],'sender_id'=>$row['sender_id'],'message'=>$row['message'],'is_read'=>(bool) $row['is_read'],'created_at'=>$row['created_at'],];}return $msgs;}private function getQuickReplies():array{$res=$this->db->query("SELECT trigger_word, display_text AS display, response\n             FROM quick_replies\n             WHERE is_active = 1\n             ORDER BY sort_order ASC, id ASC");if(!$res)return[];$list=[];while($row=$res->fetch_assoc()){$list[]=['trigger'=>$row['trigger_word'],'display'=>$row['display'],'response'=>$row['response'],];}return $list;}private function saveMsg(int $convId,string $senderType,?int $senderId,string $message,int $isRead):int{$stmt=$this->db->prepare("INSERT INTO chat_messages (conversation_id, sender_type, sender_id, message, is_read)\n             VALUES (?, ?, ?, ?, ?)");$stmt->bind_param('isisi',$convId,$senderType,$senderId,$message,$isRead);$stmt->execute();return (int) $stmt->insert_id;}private function doMarkRead(int $convId,string $senderType):int{$stmt=$this->db->prepare("UPDATE chat_messages\n             SET is_read = 1\n             WHERE conversation_id = ? AND sender_type = ? AND is_read = 0");$stmt->bind_param('is',$convId,$senderType);$stmt->execute();return $stmt->affected_rows;}private function doMarkUserMsgsRead(int $convId):void{$stmt=$this->db->prepare("SELECT sa.is_online\n             FROM chat_conversations cc\n             JOIN support_agents sa ON sa.id = cc.support_agent_id\n             WHERE cc.id = ? LIMIT 1");$stmt->bind_param('i',$convId);$stmt->execute();$row=$stmt->get_result()->fetch_assoc();if($row&&$row['is_online']==1){$this->doMarkRead($convId,'user');}}private function getAutoReply(string $message):?string{$lower=mb_strtolower(trim($message));$res=$this->db->query("SELECT trigger_word, response FROM quick_replies WHERE is_active = 1");if($res){while($row=$res->fetch_assoc()){if(mb_strpos($lower,mb_strtolower($row['trigger_word']))!==false){return $row['response'];}}}$keywords=[['words'=>['hello','hi','hey','namaste'],'reply'=>"Hello! 👋 How can I assist you today?"],['words'=>['thank','thanks','shukriya','dhanyawad'],'reply'=>"You're welcome! 😊 Is there anything else I can help you with?"],['words'=>['help','support','issue','problem'],'reply'=>"I'm here to help! You can ask me about bookings, payments, cancellations, or room details. What would you like to know?"],['words'=>['booking','reservation'],'reply'=>"For booking queries, please share your booking ID and I'll look into it right away. 🏠"],['words'=>['cancel','cancellation'],'reply'=>"To cancel a booking, go to My Bookings → Select the booking → Cancel. Need help with a specific booking?"],['words'=>['payment','refund','paid'],'reply'=>"Refunds are processed within 5-7 working days. Please share your booking ID so I can track the status."],['words'=>['room','property','amenity','amenities'],'reply'=>"Sure! You can view all amenities on the room details page. Want me to help you find specific details?"],['words'=>['price','cost','rate','charges'],'reply'=>"Room rates vary by property and dates. Check the room listing for the most accurate pricing. Anything specific I can help with?"],['words'=>['check in','check-in','checkin'],'reply'=>"Check-in time is typically 12:00 PM. You'll receive a confirmation message on the day of check-in with details. 🔑"],['words'=>['check out','check-out','checkout'],'reply'=>"Check-out time is typically 11:00 AM. You'll get a reminder notification before checkout. ⏰"],['words'=>['bye','goodbye','alvida'],'reply'=>"Goodbye! 👋 Don't hesitate to reach out if you need anything. Have a great day!"],];foreach($keywords as $kw){foreach($kw['words']as $w){if(mb_strpos($lower,$w)!==false){return $kw['reply'];}}}return null;}private function fail(string $msg,int $code=200):void{http_response_code($code);echo json_encode(['success'=>false,'message'=>$msg]);}}